import { useState } from "react";
import {
  Box,
  Card,
  CardContent,
  Typography,
  TextField,
  Button,
  Grid,
  Snackbar,
  Alert,
  Dialog,
  DialogContent,
} from "@mui/material";
import ContentCopyIcon from "@mui/icons-material/ContentCopy";
import API from "../../api/axios";

export default function ProjectSetup() {
  const [userForm, setUserForm] = useState({
    username: "",
    password: "",
    confirmPassword: "",
  });

  const [projectForm, setProjectForm] = useState({
    projectName: "",
    description: "",
    startDate: "",
    endDate: "",
  });

  const [createdUser, setCreatedUser] = useState(null);
  const [openDialog, setOpenDialog] = useState(false);

  const [loadingUser, setLoadingUser] = useState(false);
  const [loadingProject, setLoadingProject] = useState(false);

  const [snackbar, setSnackbar] = useState({
    open: false,
    message: "",
    severity: "success",
  });

  // 🔹 HANDLERS
  const handleUserChange = (field) => (e) => {
    setUserForm({ ...userForm, [field]: e.target.value });
  };

  const handleProjectChange = (field) => (e) => {
    setProjectForm({ ...projectForm, [field]: e.target.value });
  };

  // 🔹 COPY FUNCTION
  const handleCopy = () => {
    const text = `Username: ${createdUser.username}\nPassword: ${createdUser.password}`;
    navigator.clipboard.writeText(text);

    setSnackbar({
      open: true,
      message: "Copied to clipboard ✅",
      severity: "success",
    });
  };

  // 🚀 CREATE USER
  const handleCreateUser = async () => {
    if (loadingUser) return;

    if (userForm.password !== userForm.confirmPassword) {
      setSnackbar({
        open: true,
        message: "Passwords do not match ❌",
        severity: "error",
      });
      return;
    }

    if (!userForm.username || !userForm.password) {
      setSnackbar({
        open: true,
        message: "Fill required fields ❌",
        severity: "error",
      });
      return;
    }

    try {
      setLoadingUser(true);

      await API.post(
        "create-user/",
        {
          username: userForm.username,
          password: userForm.password,
        },
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        },
      );

      // ✅ Save & open popup
      setCreatedUser({
        username: userForm.username,
        password: userForm.password,
      });

      setOpenDialog(true);

      setUserForm({
        username: "",
        password: "",
        confirmPassword: "",
      });
    } catch (err) {
      setSnackbar({
        open: true,
        message: err.response?.data?.detail || "Error creating user ❌",
        severity: "error",
      });
    } finally {
      setLoadingUser(false);
    }
  };

  // 🚀 CREATE PROJECT
  const handleCreateProject = async () => {
    if (loadingProject) return;

    if (!projectForm.projectName) {
      setSnackbar({
        open: true,
        message: "Project name is required ❌",
        severity: "error",
      });
      return;
    }

    try {
      setLoadingProject(true);

      await API.post(
        "create-project/",
        {
          project_name: projectForm.projectName,
          description: projectForm.description,
          start_date: projectForm.startDate,
          end_date: projectForm.endDate,
        },
        {
          headers: {
            Authorization: `Bearer ${localStorage.getItem("token")}`,
          },
        },
      );

      setSnackbar({
        open: true,
        message: "Project Created Successfully ✅",
        severity: "success",
      });

      setProjectForm({
        projectName: "",
        description: "",
        startDate: "",
        endDate: "",
      });
    } catch (err) {
      setSnackbar({
        open: true,
        message: err.response?.data?.detail || "Error creating project ❌",
        severity: "error",
      });
    } finally {
      setLoadingProject(false);
    }
  };

  return (
    <Box
      sx={{
        minHeight: "100vh",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        background: "linear-gradient(135deg, #e3f2fd, #ffffff)",
        p: 2,
      }}
    >
      <Grid container spacing={3} maxWidth={900}>
        {/* CREATE USER */}
        <Grid item xs={12} md={6}>
          <Card sx={{ p: 3, borderRadius: 4 }}>
            <CardContent>
              <Typography variant="h6" mb={2} fontWeight="bold">
                Create User
              </Typography>

              <TextField
                fullWidth
                label="Username"
                margin="normal"
                value={userForm.username}
                onChange={handleUserChange("username")}
              />

              <TextField
                fullWidth
                label="Password"
                type="password"
                margin="normal"
                value={userForm.password}
                onChange={handleUserChange("password")}
              />

              <TextField
                fullWidth
                label="Confirm Password"
                type="password"
                margin="normal"
                value={userForm.confirmPassword}
                onChange={handleUserChange("confirmPassword")}
              />

              <Button
                fullWidth
                variant="contained"
                sx={{ mt: 2, borderRadius: 5 }}
                onClick={handleCreateUser}
                disabled={loadingUser}
              >
                {loadingUser ? "Creating..." : "Create User"}
              </Button>
            </CardContent>
          </Card>
        </Grid>

        {/* CREATE PROJECT */}
        <Grid item xs={12} md={6}>
          <Card sx={{ p: 3, borderRadius: 4 }}>
            <CardContent>
              <Typography variant="h6" mb={2} fontWeight="bold">
                Create Project
              </Typography>

              <TextField
                fullWidth
                label="Project Name"
                margin="normal"
                value={projectForm.projectName}
                onChange={handleProjectChange("projectName")}
              />

              <TextField
                fullWidth
                label="Description"
                margin="normal"
                value={projectForm.description}
                onChange={handleProjectChange("description")}
              />

              <TextField
                fullWidth
                label="Start Date"
                type="date"
                margin="normal"
                InputLabelProps={{ shrink: true }}
                value={projectForm.startDate}
                onChange={handleProjectChange("startDate")}
              />

              <TextField
                fullWidth
                label="End Date"
                type="date"
                margin="normal"
                InputLabelProps={{ shrink: true }}
                value={projectForm.endDate}
                onChange={handleProjectChange("endDate")}
              />

              <Button
                fullWidth
                variant="contained"
                sx={{ mt: 2, borderRadius: 5 }}
                onClick={handleCreateProject}
                disabled={loadingProject}
              >
                {loadingProject ? "Creating..." : "Create Project"}
              </Button>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      {/* 🔥 POPUP DIALOG */}
      <Dialog open={openDialog} onClose={() => setOpenDialog(false)}>
        <DialogContent sx={{ p: 4, textAlign: "center" }}>
          <Typography variant="h6" fontWeight="bold" mb={2}>
            🎉 User Created!
          </Typography>

          <Typography>
            <b>Username:</b> {createdUser?.username}
          </Typography>
          <Typography mb={2}>
            <b>Password:</b> {createdUser?.password}
          </Typography>

          <Button
            startIcon={<ContentCopyIcon />}
            variant="outlined"
            onClick={handleCopy}
          >
            Copy Credentials
          </Button>
        </DialogContent>
      </Dialog>

      {/* 🔥 SNACKBAR */}
      <Snackbar
        open={snackbar.open}
        autoHideDuration={3000}
        onClose={() => setSnackbar({ ...snackbar, open: false })}
      >
        <Alert severity={snackbar.severity} variant="filled">
          {snackbar.message}
        </Alert>
      </Snackbar>
    </Box>
  );
}
